import 'package:bookly/Core/Utils/Widget/custom_books_image.dart';import 'package:bookly/Core/Utils/Widget/custom_loading.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../../../../Config/Routes/next_screen.dart';import '../../../../../Config/Routes/route_app.dart';import '../../manager/NewBooks/new_books_cubit.dart';class NovelsBookBuilder extends StatelessWidget {  final double? aspectRatio;  const NovelsBookBuilder({super.key, this.aspectRatio});  @override  Widget build(BuildContext context) {    return BlocBuilder<NewBooksCubit, NewBooksState>(      builder: (context, state) {        if (state is GetBooksPictureSuccess) {          return _body(context, state);        } else if (state is GetBooksPictureFailure) {          return Text(state.error);        } else {          return const CustomLoading();        }      },    );  }  Padding _body(BuildContext context, GetBooksPictureSuccess state) => Padding(        padding: const EdgeInsets.only(left: 35, top: 20, bottom: 40),        child: SizedBox(          height: aspectRatio ?? MediaQuery.of(context).size.height * .27,          child: ListView.separated(              scrollDirection: Axis.horizontal,              itemBuilder: (context, index) {                return InkWell(                    onTap: () => pushNext(context, AppRoutes.viewBooksRoute,                        arguments: state.books[index]),                    child: CustomBooksImage(                        imageUrl: state.books[index].imageLinks!));              },              separatorBuilder: (context, index) => const SizedBox(                    width: 20,                  ),              itemCount: state.books.length),        ),      );}